export const meta = {
  name: 'init-explore-opencore-sdk',
  description: 'Initialize knowledge base and explore OpenCoreSDK codebase',
  phases: [
    { title: '项目扫描', detail: '扫描项目结构和依赖' },
    { title: '架构分析', detail: '分析架构层次和模块依赖' },
    { title: '领域分析', detail: '提取业务领域和核心概念' },
    { title: '文件批量分析', detail: '并行深度分析核心源文件' },
    { title: '知识整合', detail: '整合分析结果生成知识报告' },
    { title: '知识沉淀', detail: '保存关键知识到 docs/exploration/' },
    { title: '索引更新', detail: '更新文档索引和 CLAUDE.md' },
    { title: '系统初始化', detail: '初始化知识管理系统' },
    { title: '验证', detail: '验证所有组件正常工作' }
  ]
}

// 工作目录
const projectDir = '/home/cwtrocks/OpenCoreSDK'

phase('项目扫描')
const scanResult = await agent(
  `扫描项目 ${projectDir}，识别：1) 编程语言和构建系统 2) 文件数量和目录结构 3) 第三方依赖 4) 关键入口点`,
  { agentType: 'understand-anything:project-scanner' }
)

phase('架构分析')
const archResult = await agent(
  `分析 ${projectDir} 的架构层次：1) 识别逻辑分层 2) 分析模块间依赖 3) 识别设计模式 4) 绘制组件依赖图 5) 分析数据流向`,
  { agentType: 'understand-anything:architecture-analyzer' }
)

phase('领域分析')
const domainResult = await agent(
  `分析 ${projectDir} 的业务领域：1) 提取业务流程和领域概念 2) 识别核心业务逻辑 3) 分析领域模型 4) 提取业务规则和约束`,
  { agentType: 'understand-anything:domain-analyzer' }
)

// 发现关键源文件
const criticalFiles = await findCriticalSourceFiles(projectDir)
log(`发现 ${criticalFiles.length} 个关键源文件待分析`)

phase('文件批量分析')
const fileAnalyses = await pipeline(
  criticalFiles.slice(0, 20), // 限制并行数量
  async (file) => await agent(
    `深度分析文件 ${file}：提取类、函数、算法、数据结构、关键设计决策`,
    { phase: '文件批量分析', label: file.split('/').pop() }
  )
)

phase('知识整合')
const knowledgeReport = await agent(
  `整合 ${projectDir} 的所有分析结果，生成统一知识报告，包括：项目概览、架构决策、核心领域知识、学习路径建议`,
  { schema: {
    type: 'object',
    properties: {
      overview: { type: 'string' },
      architecture: { type: 'array' },
      domains: { type: 'array' },
      learningPath: { type: 'array' }
    }
  }}
)

return { scanResult, archResult, domainResult, fileAnalyses, knowledgeReport }

async function findCriticalSourceFiles(dir) {
  // 查找关键源文件（C++/C/头文件）
  const result = await agent(`在 ${dir} 中递归查找所有 .cpp .h .hpp .c 文件，返回绝对路径列表，重点关注核心模块`)
  return result.files || []
}

